  1	import { type FC, useEffect, useState } from 'react';
  2	
  3	import ModalForm from '@components/ModalForm/ModalForm';
  4	import { type IoK8sApiCoreV1Secret, SecretModel } from '@kubev2v/types';
  5	import {
  6	  getGroupVersionKindForModel,
  7	  useK8sWatchResource,
  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import { Checkbox, FormGroup, Stack } from '@patternfly/react-core';
 10	import { getNamespace } from '@utils/crds/common/selectors';
 11	import { getLUKSSecretName, getPlanVirtualMachines } from '@utils/crds/plans/selectors';
 12	import { isEmpty } from '@utils/helpers';
 13	import { useForkliftTranslation } from '@utils/i18n';
 14	
 15	import type { EditPlanProps, EnhancedPlanSpecVms } from '../../utils/types';
 16	
 17	import EditLUKSModalAlert from './components/EditLUKSModalAlert';
 18	import EditLUKSModalBody from './components/EditLUKSModalBody';
 19	import { onDiskDecryptionConfirm } from './utils/utils';
 20	import LUKSPassphraseInputList from './LUKSPassphraseInputList';
 21	
 22	const EditLUKSEncryptionPasswords: FC<EditPlanProps> = ({ resource }) => {
 23	  const { t } = useForkliftTranslation();
 24	
 25	  const secretName = getLUKSSecretName(resource);
 26	  const secretNamespace = getNamespace(resource);
 27	  const allVMsHasMatchingLuks = getPlanVirtualMachines(resource).every(
 28	    (vm) => vm.luks?.name === secretName,
 29	  );
 30	
 31	  const [secret] = useK8sWatchResource<IoK8sApiCoreV1Secret>({
 32	    groupVersionKind: getGroupVersionKindForModel(SecretModel),
 33	    name: secretName,
 34	    namespace: secretNamespace,
 35	  });
 36	
 37	  const [value, setValue] = useState<string[]>([]);
 38	  const [nbdeClevis, setNbdeClevis] = useState<boolean>(false);
 39	
 40	  // Get current NBDE setting from the first VM (all VMs have the same setting)
 41	  useEffect(() => {
 42	    const vms = getPlanVirtualMachines(resource) as EnhancedPlanSpecVms[];
 43	    if (!isEmpty(vms)) {
 44	      setNbdeClevis(Boolean(vms[0]?.nbdeClevis ?? false));
 45	    }
 46	  }, [resource]);
 47	
 48	  useEffect(() => {
 49	    if (secret?.data && !nbdeClevis) {
 50	      const decoded = Object.values(secret.data)
 51	        .map((secretData) => {
 52	          try {
 53	            return atob(secretData);
 54	          } catch {
 55	            return '';
 56	          }
 57	        })
 58	        .filter(Boolean);
 59	
 60	      setValue(decoded);
 61	    }
 62	  }, [secret?.data, nbdeClevis]);
 63	
 64	  // Clear passphrases when NBDE is enabled
 65	  useEffect(() => {
 66	    if (nbdeClevis) {
 67	      setValue([]);
 68	    }
 69	  }, [nbdeClevis]);
 70	
 71	  if (secretName && !secret?.data) return null;
 72	
 73	  return (
 74	    <ModalForm
 75	      title={t('Disk decryption')}
 76	      onConfirm={async () =>
 77	        onDiskDecryptionConfirm({
 78	          nbdeClevis,
 79	          newValue: JSON.stringify(value),
 80	          resource,
 81	        })
 82	      }
 83	    >
 84	      <Stack hasGutter>
 85	        <EditLUKSModalBody />
 86	
 87	        <Checkbox
 88	          id="nbde-clevis-checkbox-modal"
 89	          isChecked={nbdeClevis}
 90	          onChange={(_event, checked) => {
 91	            setNbdeClevis(checked);
 92	          }}
 93	          label={t('Use network-bound disk encryption (NBDE/Clevis)')}
 94	          className="pf-v6-u-mt-lg"
 95	        />
 96	
 97	        {!nbdeClevis && <FormGroup label={t('Passphrases for LUKS encrypted devices')} />}
 98	      </Stack>
 99	      {!nbdeClevis && <LUKSPassphraseInputList value={value} onChange={setValue} />}
100	      <EditLUKSModalAlert shouldRender={!allVMsHasMatchingLuks} />
101	    </ModalForm>
102	  );
103	};
104	
105	export default EditLUKSEncryptionPasswords;

