 16	} from '@patternfly/react-core';
 17	import { useForkliftTranslation } from '@utils/i18n';
 18	
 19	type ModalFormProps = {
 20	  title: ReactNode;
 21	  children: ReactNode;
 22	  onConfirm: () => Promise<K8sResourceCommon>;
 23	  variant?: ModalVariant;
 24	  confirmLabel?: string;
 25	  cancelLabel?: string;
 26	  className?: string;
 27	  confirmVariant?: ButtonVariant;
 28	  isDisabled?: boolean;
 29	  additionalAction?: ButtonProps;
 30	  testId?: string;
 31	};
 32	
 33	const ModalForm: FC<ModalFormProps> = ({
 34	  additionalAction,
 35	  cancelLabel,
 36	  children,
 37	  className,
 38	  confirmLabel,
 39	  confirmVariant,
 40	  isDisabled,
 41	  onConfirm,
 42	  testId,
 43	  title,
 44	  variant = ModalVariant.small,
 45	}) => {
 46	  const { t } = useForkliftTranslation();
 47	  const { toggleModal } = useModal();
 48	  const [isLoading, setIsLoading] = useState(false);
 49	  const [error, setError] = useState<string | null>(null);
 50	
 51	  const handleConfirm = useCallback(async () => {
 52	    setIsLoading(true);
 53	    setError(null);
 54	
 55	    try {
 56	      await onConfirm();
 57	      toggleModal();
 58	    } catch (e) {
 59	      setError((e as Error)?.message ?? e?.toString());
 60	    } finally {
 61	      setIsLoading(false);
 62	    }
 63	  }, [onConfirm, toggleModal]);
 64	
 65	  return (
 66	    <Modal
 67	      variant={variant}
 68	      isOpen
 69	      position="top"
 70	      onClose={toggleModal}
 71	      data-testid={testId}
 72	      className={className}
 73	    >
 74	      <ModalHeader title={title} />
 75	      <ModalBody>
 76	        {children}
 77	
 78	        {error && (
 79	          <Alert title={t('Error')} variant={AlertVariant.danger} isInline>
 80	            {t('{{errorMessage}}', { errorMessage: error })}
 81	          </Alert>
 82	        )}
 83	      </ModalBody>
 84	      <ModalFooter>
 85	        <Button
 86	          key="confirm"
 87	          variant={confirmVariant ?? ButtonVariant.primary}
 88	          onClick={handleConfirm}
 89	          isLoading={isLoading}
 90	          isDisabled={isLoading || Boolean(error) || isDisabled}
 91	          data-testid="modal-confirm-button"
 92	        >
 93	          {confirmLabel ?? t('Save')}
 94	        </Button>
 95	        {additionalAction && (
 96	          <Button key="secondary" {...additionalAction}>
 97	            {additionalAction?.children}
 98	          </Button>
 99	        )}
100	        <Button
101	          key="cancel"
102	          variant={ButtonVariant.secondary}
103	          onClick={toggleModal}
104	          data-testid="modal-cancel-button"
105	        >
106	          {cancelLabel ?? t('Cancel')}
107	        </Button>
108	      </ModalFooter>
109	    </Modal>
110	  );
111	};
112	
113	export default ModalForm;

