  9	
 10	const mockOnDiskDecryptionConfirm = jest.fn().mockResolvedValue(undefined);
 11	jest.mock('../utils/utils', () => ({
 12	  onDiskDecryptionConfirm: jest.fn((...args) => mockOnDiskDecryptionConfirm(...args)),
 13	}));
 14	
 15	const mockGetLUKSSecretName = jest.fn();
 16	const mockGetPlanVirtualMachines = jest.fn();
 17	jest.mock('@utils/crds/plans/selectors', () => ({
 18	  getLUKSSecretName: jest.fn((...args) => mockGetLUKSSecretName(...args)),
 19	  getPlanVirtualMachines: jest.fn((...args) => mockGetPlanVirtualMachines(...args)),
 20	}));
 21	
 22	const mockGetNamespace = jest.fn();
 23	jest.mock('@utils/crds/common/selectors', () => ({
 24	  getNamespace: jest.fn((...args) => mockGetNamespace(...args)),
 25	}));
 26	
 27	const mockUseK8sWatchResource = jest.fn();
 28	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
 29	  getGroupVersionKindForModel: jest.fn(),
 30	  useK8sWatchResource: jest.fn((...args) => mockUseK8sWatchResource(...args)),
 31	}));
 32	
 33	jest.mock(
 34	  '../components/EditLUKSModalAlert',
 35	  () =>
 36	    ({ shouldRender }: { shouldRender: any }) =>
 37	      shouldRender ? <div data-testid="luks-modal-alert" /> : null,
 38	);
 39	jest.mock('../components/EditLUKSModalBody', () => () => <div data-testid="luks-modal-body" />);
 40	jest.mock(
 41	  '../LUKSPassphraseInputList',
 42	  () =>
 43	    ({ value, onChange }: { value: any; onChange: any }) => (
 44	      <div data-testid="luks-passphrase-input-list">
 45	        <div>Passphrases: {value.join(', ')}</div>
 46	        <button data-testid="add-passphrase" onClick={() => onChange([...value, 'new-passphrase'])}>
 47	          Add
 48	        </button>
 49	      </div>
 50	    ),
 51	);
 52	
 53	const mockPlan = {
 54	  metadata: { name: 'test-plan', namespace: 'test-namespace' },
 55	  spec: { vms: [] },
 56	} as unknown as V1beta1Plan;
 57	
 58	const renderWithModal = (component: React.ReactElement) => render(<ModalHOC>{component}</ModalHOC>);
 59	
 60	describe('EditLUKSEncryptionPasswords', () => {
 61	  beforeEach(() => {
 62	    jest.clearAllMocks();
 63	    mockGetLUKSSecretName.mockReturnValue('test-secret');
 64	    mockGetNamespace.mockReturnValue('test-namespace');
 65	    mockGetPlanVirtualMachines.mockReturnValue([]);
 66	    mockUseK8sWatchResource.mockReturnValue([{ data: {} }, false, null]);
 67	  });
 68	
 69	  it('initializes NBDE state from VM data', () => {
 70	    mockGetPlanVirtualMachines.mockReturnValue([{ nbdeClevis: true }]);
 71	
 72	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
 73	
 74	    const checkbox = screen.getByLabelText('Use network-bound disk encryption (NBDE/Clevis)');
 75	    expect(checkbox).toBeChecked();
 76	  });
 77	
 78	  it('toggles NBDE checkbox', async () => {
 79	    const user = userEvent.setup();
 80	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
 81	
 82	    const checkbox = screen.getByLabelText('Use network-bound disk encryption (NBDE/Clevis)');
 83	    expect(checkbox).not.toBeChecked();
 84	
 85	    await user.click(checkbox);
 86	    expect(checkbox).toBeChecked();
 87	  });
 88	
 89	  it('shows passphrase fields when NBDE is disabled', () => {
 90	    mockGetPlanVirtualMachines.mockReturnValue([{ nbdeClevis: false }]);
 91	
 92	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
 93	
 94	    expect(screen.getByText('Passphrases for LUKS encrypted devices')).toBeInTheDocument();
 95	    expect(screen.getByTestId('luks-passphrase-input-list')).toBeInTheDocument();
 96	  });
 97	
 98	  it('hides passphrase fields when NBDE is enabled', async () => {
 99	    const user = userEvent.setup();
100	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
101	
102	    const checkbox = screen.getByLabelText('Use network-bound disk encryption (NBDE/Clevis)');
103	    await user.click(checkbox);
104	
105	    expect(screen.queryByText('Passphrases for LUKS encrypted devices')).not.toBeInTheDocument();
106	  });
107	
108	  it('loads existing passphrases from secret', async () => {
109	    mockGetPlanVirtualMachines.mockReturnValue([{ nbdeClevis: false }]);
110	    mockUseK8sWatchResource.mockReturnValue([
111	      { data: { pass1: btoa('test-pass-1'), pass2: btoa('test-pass-2') } },
112	      false,
113	      null,
114	    ]);
115	
116	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
117	
118	    await waitFor(() => {
119	      expect(screen.getByText('Passphrases: test-pass-1, test-pass-2')).toBeInTheDocument();
120	    });
121	  });
122	
123	  it('clears passphrases when NBDE is enabled', async () => {
124	    const user = userEvent.setup();
125	    mockUseK8sWatchResource.mockReturnValue([{ data: { pass1: btoa('test-pass') } }, false, null]);
126	
127	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
128	
129	    await waitFor(() => {
130	      expect(screen.getByText('Passphrases: test-pass')).toBeInTheDocument();
131	    });
132	
133	    const checkbox = screen.getByLabelText('Use network-bound disk encryption (NBDE/Clevis)');
134	    await user.click(checkbox);
135	    await user.click(checkbox); // Disable to see cleared state
136	
137	    expect(screen.getByText(/Passphrases:/)).toBeInTheDocument();
138	  });
139	
140	  it('submits form with correct NBDE state', async () => {
141	    const user = userEvent.setup();
142	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
143	
144	    const checkbox = screen.getByLabelText('Use network-bound disk encryption (NBDE/Clevis)');
145	    await user.click(checkbox);
146	
147	    const confirmButton = screen.getByRole('button', { name: /save/i });
148	    await user.click(confirmButton);
149	
150	    await waitFor(() => {
151	      expect(mockOnDiskDecryptionConfirm).toHaveBeenCalledWith({
152	        nbdeClevis: true,
153	        newValue: JSON.stringify([]),
154	        resource: mockPlan,
155	      });
156	    });
157	  });
158	
159	  it('shows alert for mismatched LUKS settings', () => {
160	    mockGetLUKSSecretName.mockReturnValue('secret-1');
161	    mockGetPlanVirtualMachines.mockReturnValue([
162	      { luks: { name: 'secret-1' } },
163	      { luks: { name: 'secret-2' } },
164	    ]);
165	
166	    renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
167	
168	    expect(screen.getByTestId('luks-modal-alert')).toBeInTheDocument();
169	  });
170	
171	  it('handles missing secret data gracefully', () => {
172	    mockGetLUKSSecretName.mockReturnValue('test-secret');
173	    mockUseK8sWatchResource.mockReturnValue([{ data: null }, false, null]);
174	
175	    const { container } = renderWithModal(<EditLUKSEncryptionPasswords resource={mockPlan} />);
176	
177	    expect(container.firstChild).toBeNull();
178	  });
179	});

